import { describe, it, expect } from '@jest/globals';
import {
  getRowDivisionName, isSpruceRow, isPopRow, isBuyerScopeRow, canSeeBuyerMarginValue,
} from './buyer-margin-visibility';

describe('buyer-margin-visibility', () => {
  describe('getRowDivisionName', () => {
    it('reads a raw string Div (as loaded)', () => {
      expect(getRowDivisionName({ Div: 'Spruce non-Lic' })).toBe('spruce non-lic');
    });
    it('reads a { title } Div (after edit)', () => {
      expect(getRowDivisionName({ Div: { title: 'POP Lic' } })).toBe('pop lic');
    });
    it('returns empty string for missing/null Div', () => {
      expect(getRowDivisionName({})).toBe('');
      expect(getRowDivisionName({ Div: null })).toBe('');
      expect(getRowDivisionName(null)).toBe('');
    });
  });

  describe('division predicates', () => {
    it('treats both Spruce variants as Spruce', () => {
      expect(isSpruceRow({ Div: 'Spruce Lic' })).toBe(true);
      expect(isSpruceRow({ Div: 'Spruce non-Lic' })).toBe(true);
      expect(isSpruceRow({ Div: { title: 'Spruce non-Lic' } })).toBe(true);
    });
    it('treats POP Lic as POP, not Spruce', () => {
      expect(isPopRow({ Div: 'POP Lic' })).toBe(true);
      expect(isSpruceRow({ Div: 'POP Lic' })).toBe(false);
    });
    it('POP and Spruce are both in buyer scope', () => {
      expect(isBuyerScopeRow({ Div: 'POP Lic' })).toBe(true);
      expect(isBuyerScopeRow({ Div: 'Spruce Lic' })).toBe(true);
    });
    it('factory-import "Gen,Lic" and unknown divisions are out of scope', () => {
      expect(isBuyerScopeRow({ Div: 'Gen,Lic' })).toBe(false);
      expect(isSpruceRow({ Div: 'Gen,Lic' })).toBe(false);
      expect(isPopRow({ Div: 'Gen,Lic' })).toBe(false);
      expect(isBuyerScopeRow({})).toBe(false);
    });
  });

  describe('canSeeBuyerMarginValue', () => {
    it('nobody sees the value without the toggle', () => {
      expect(canSeeBuyerMarginValue({ role: 'admin', canSeeBuyerCols: false, data: { Div: 'Spruce Lic' } })).toBe(false);
      expect(canSeeBuyerMarginValue({ role: 'sales', canSeeBuyerCols: false, data: { Div: 'Spruce Lic' } })).toBe(false);
    });
    it('admin sees Spruce AND POP', () => {
      expect(canSeeBuyerMarginValue({ role: 'admin', canSeeBuyerCols: true, data: { Div: 'Spruce non-Lic' } })).toBe(true);
      expect(canSeeBuyerMarginValue({ role: 'admin', canSeeBuyerCols: true, data: { Div: 'POP Lic' } })).toBe(true);
    });
    it('toggled salesman (Adam) sees Spruce only — POP stays blank', () => {
      expect(canSeeBuyerMarginValue({ role: 'sales', canSeeBuyerCols: true, data: { Div: 'Spruce Lic' } })).toBe(true);
      expect(canSeeBuyerMarginValue({ role: 'sales', canSeeBuyerCols: true, data: { Div: 'POP Lic' } })).toBe(false);
    });
    it('out-of-scope divisions are blank for everyone', () => {
      expect(canSeeBuyerMarginValue({ role: 'admin', canSeeBuyerCols: true, data: { Div: 'Gen,Lic' } })).toBe(false);
      expect(canSeeBuyerMarginValue({ role: 'sales', canSeeBuyerCols: true, data: { Div: 'Gen,Lic' } })).toBe(false);
    });
  });
});

