  agInit(params: any): void {
    this.params = params;
    this.setInitialState(this.params);

    // only start edit if key pressed is a number, not a letter
    // Check both charPress (legacy) and eventKey (AG Grid v34+)
    const initialChar = params.charPress || params.eventKey;
    this.cancelBeforeStart =
      initialChar && !'1234567890.'.includes(initialChar);
  }

  setInitialState(params: any) {
    let startValue;
    let highlightAllOnFocus = true;

    // Get the initial character - check both charPress (legacy) and eventKey (AG Grid v34+)
    const initialChar = params.charPress || params.eventKey;

    if (params.keyPress === KEY_BACKSPACE || params.keyPress === KEY_DELETE) {
      // if backspace or delete pressed, we clear the cell
      startValue = '';
    } else if (initialChar && '1234567890.'.includes(initialChar)) {
      // if a number was pressed, we start with that number
      startValue = initialChar;
      highlightAllOnFocus = false;
    } else {
      // otherwise we start with the current value
      startValue = params.value;
      if (params.keyPress === KEY_F2) {
        highlightAllOnFocus = false;
      }
    }

    this.value = startValue;
    this.highlightAllOnFocus = highlightAllOnFocus;
  }

  getValue(): any {
    // Convert string to number before returning
    // Handle empty string, null, or undefined
    if (this.value === null || this.value === undefined || this.value === '') {
      return null;
    }
    const numValue = parseFloat(this.value);
    return isNaN(numValue) ? null : numValue;
  }

  isCancelBeforeStart(): boolean {
    return this.cancelBeforeStart;
  }

  // will reject the number if it greater than 1,000,000
  // not very practical, but demonstrates the method.
  isCancelAfterEnd(): boolean {
    return this.value > 1000000;
  }

  onKeyDown(event: any): void {
    if (this.isLeftOrRight(event) || this.deleteOrBackspace(event)) {
      event.stopPropagation();
      return;
    }

    // ESC: cancel the edit and restore the previous value (like Excel)
    if (this.getCharCodeFromEvent(event) === 27) {
      this.params.api.stopEditing(true);
      return;
    }

    if (
      !this.finishedEditingPressed(event) &&
      !this.isKeyPressedNumeric(event)
    ) {
      if (event.preventDefault) event.preventDefault();
    }
  }

