  // Buyer Target / Buyer Margin % — 16 salesman columns (2 × 8 quote types).
  describe('Buyer Target / Buyer Margin % columns', () => {
    const TYPES = ['gen_fob', 'gen_mddp', 'gen_poe', 'gen_whse', 'lic_fob', 'lic_mddp', 'lic_poe', 'lic_whse'];

    test('all 16 columns exist, numeric, gated to admin+sales', () => {
      for (const t of TYPES) {
        for (const suffix of ['buyer_target', 'buyer_margin']) {
          const col = colById(`${t}_${suffix}`);
          expect(typeof col.comparator).toBe('function'); // numeric sort
          const roles = (col as { context?: { roles?: string[] } }).context?.roles;
          expect(roles).toEqual(['admin', 'sales']);
        }
      }
    });

    test('buyer_margin columns are read-only; buyer_target columns are editable', () => {
      for (const t of TYPES) {
        expect(colById(`${t}_buyer_margin`).editable).toBe(false);
        // buyer_target inherits editable:true from commonDefaults (row-level editability
        // is enforced by the component valueSetter/editable fn, not here).
        expect(colById(`${t}_buyer_target`).editable).not.toBe(false);
      }
    });
  });

  // R4: numeric columns must sort numerically, not lexicographically ("10" before "2").
  describe('numeric columns (R4 numeric sort)', () => {
    const numericIds = [
      'fob_cost',
      'duty_rate',
      'freight',
      'landed_cost',
      'dilution',
      'logistics_load',
      'gen_fob_sell_price',
      'gen_fob_margin',
      'lic_fob_sell_price',
      'lic_fob_margin',
      'cbm_pc',
      // Previously sorted lexicographically — fixed alongside the Buyer Margin work.
      'carton_length',
      'carton_width',
      'carton_height',
      'agent',
      // Buyer Target / Buyer Margin % (numeric).
      'gen_fob_buyer_target',
      'gen_fob_buyer_margin',
      'lic_mddp_buyer_target',
      'lic_mddp_buyer_margin',
    ];

    test('numeric columns expose a function comparator and are sortable', () => {
      for (const id of numericIds) {
        const col = colById(id);
        if (typeof col.comparator !== 'function') {
          throw new Error(`expected colId "${id}" to have a function comparator`);
        }
        expect(col.sortable).toBe(true);
      }
    });

    test('comparator sorts as numbers, not strings ("10" after "2")', () => {
      const comparator = colById('fob_cost').comparator as (a: any, b: any) => number;
      // Lexicographic order would put "10" before "2"; numeric order must not.
      expect(comparator('10', '2')).toBeGreaterThan(0);
      expect(comparator('2', '10')).toBeLessThan(0);
      expect(comparator('5', '5')).toBe(0);
      expect(comparator(2, 10)).toBeLessThan(0);
    });

    test('comparator pushes blank/non-numeric values consistently', () => {
      const comparator = colById('fob_cost').comparator as (a: any, b: any) => number;
      expect(comparator(null, null)).toBe(0);
      expect(comparator('', '')).toBe(0);
      expect(comparator(null, '5')).toBe(-1);
      expect(comparator('5', null)).toBe(1);
      expect(comparator('abc', '5')).toBe(-1);
    });

    test('the "numeric" flag is internal and not leaked onto the colDef', () => {
      expect((colById('fob_cost') as any).numeric).toBeUndefined();
    });
  });

