  private applyAutoFormatters(columns: any[]) {
    return columns.map(col => {
      if (!col.field?.toLowerCase().includes('date')) return col;
      const updated: any = { ...col, valueFormatter: this.dateFormatter };
      // Resolve the comparator string to the actual function — the config
      // stores "dateComparator" as a string which AG-Grid cannot call as a function.
      // NOTE: No aggFunc — postSortRows handles group ordering by newest child date.
      // Adding aggFunc to ANY column activates AG-Grid's aggregation pipeline for
      // group rows which interferes with valueSetter/onCellValueChanged for calculated
      // columns (FOB Cost, CBM/pc, Landed Cost, etc.).
      if (col.field === 'Date Modified') {
        updated.comparator = this.dateComparator.bind(this);
      }
      return updated;
    });
  }

